const {
  Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell,
  WidthType, ShadingType, BorderStyle, AlignmentType, PageOrientation, VerticalAlign,
  ExternalHyperlink
} = require("docx");

const COLORS = {
  critical: "C00000",
  high: "E36C09",
  medium: "BF8F00",
  info: "2E74B5",
  pass: "548235",
  headerFill: "1F3864",
  altRow: "F2F2F2",
};

const FONT = "Calibri";
const MONO = "Consolas";

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 160 },
    children: [new TextRun({ text, bold: true, color: "1F3864", font: FONT })],
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 120 },
    children: [new TextRun({ text, bold: true, color: "2E74B5", font: FONT })],
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 160 },
    children: [new TextRun({ text, font: FONT, size: 22, ...opts })],
  });
}

function bullet(text, opts = {}) {
  return new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 100 },
    children: [new TextRun({ text, font: FONT, size: 22, ...opts })],
  });
}

function severityBullet(label, color, text) {
  return new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 120 },
    children: [
      new TextRun({ text: `${label}: `, bold: true, color, font: FONT, size: 22 }),
      new TextRun({ text, font: FONT, size: 22 }),
    ],
  });
}

function codeBlock(lines) {
  return new Paragraph({
    spacing: { before: 80, after: 200 },
    shading: { type: ShadingType.CLEAR, fill: "F5F5F5" },
    border: {
      top: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      bottom: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      left: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      right: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
    },
    children: lines.flatMap((line, i) => {
      const run = new TextRun({ text: line || " ", font: MONO, size: 18, color: "333333", break: i === 0 ? 0 : 1 });
      return [run];
    }),
  });
}

function cell(text, opts = {}) {
  const { bold = false, color, fill, width, align = AlignmentType.LEFT, size = 20 } = opts;
  return new TableCell({
    width: { size: width, type: WidthType.DXA },
    shading: fill ? { type: ShadingType.CLEAR, fill } : undefined,
    verticalAlign: VerticalAlign.CENTER,
    margins: { top: 80, bottom: 80, left: 100, right: 100 },
    children: [
      new Paragraph({
        alignment: align,
        children: [new TextRun({ text, bold, color, font: FONT, size })],
      }),
    ],
  });
}

function headerCell(text, width) {
  return cell(text, { bold: true, color: "FFFFFF", fill: COLORS.headerFill, width, size: 20 });
}

// ---- Templates table ----
const templateRows = [
  ["Homepage", "/", "WebPage, BreadcrumbList, WebSite, Organization + standalone LocalBusiness"],
  ["Standard content page", "/about-us/, /contact/, /oems/, /support/, /developers/, /local-government/, /learn/, +10 more", "WebPage, BreadcrumbList, WebSite, Organization only"],
  ["Service page", "/residential/, /commercial/", "+ standalone Service"],
  ["Product / technology page", "/energy-technology/", "+ standalone Product"],
  ["Product catalog (ItemList)", "/installers/", "+ standalone ItemList of 3 Products"],
  ["Audience ItemList", "/who-we-help/, /how-we-help/", "+ standalone ItemList of Audience"],
  ["Calculator / tool page", "/zeco-energy-advisor-calculator/", "+ standalone HowTo"],
  ["Educational article page", "/reduce-power-bills/, /get-off-gas/", "+ standalone HowTo"],
  ["Regional campaign landing page", "/newcastle-solutions/", "Custom @graph: Organization, WebPage, BreadcrumbList, Service, FAQPage"],
  ["Blog post (25 total)", "/solar-for-apartments-.../, /wendys-journey-.../", "Article, WebPage, ImageObject, BreadcrumbList, WebSite, Organization, Person"],
];

const templatesTable = new Table({
  width: { size: 9350, type: WidthType.DXA },
  columnWidths: [2400, 3450, 3500],
  rows: [
    new TableRow({
      tableHeader: true,
      children: [headerCell("Template", 2400), headerCell("Example URL(s)", 3450), headerCell("Schema present", 3500)],
    }),
    ...templateRows.map((r, i) =>
      new TableRow({
        children: [
          cell(r[0], { width: 2400, fill: i % 2 ? COLORS.altRow : undefined, bold: true }),
          cell(r[1], { width: 3450, fill: i % 2 ? COLORS.altRow : undefined }),
          cell(r[2], { width: 3500, fill: i % 2 ? COLORS.altRow : undefined }),
        ],
      })
    ),
  ],
});

// ---- Validation results table ----
const validationRows = [
  ["Product (energy-technology, installers ×3)", "Product/Offer", "❌ Critical", COLORS.critical,
    "offers.price hard-coded to \"0\" with availability: InStock — not real pricing. All 4 offers reuse the same generic SVG logo instead of real product photos."],
  ["Organization/LocalBusiness (newcastle-solutions)", "Organization", "❌ Critical", COLORS.critical,
    "Literal unresolved placeholders: .../path-to-logo.png and .../path-to-hero-image.jpg (both 404). Reuses @id \"#organization\" with conflicting fields vs. the sitewide node — duplicate-@id conflict on one page."],
  ["HowTo (calculator, get-off-gas, reduce-power-bills)", "HowTo", "❌ Critical", COLORS.critical,
    "Deprecated — rich results removed Sept 2023. Two blocks are byte-for-byte identical generic boilerplate, not tailored to either page."],
  ["Organization + LocalBusiness (Home)", "Organization/LocalBusiness", "⚠ High", COLORS.high,
    "Two disconnected entities for the same brand — different logos, different sameAs lists, no shared @id. Confuses entity resolution / Knowledge Panel."],
  ["Organization (about-us)", "Organization", "⚠ High", COLORS.high,
    "Third disconnected standalone Organization node (no @id), duplicating the canonical entity with different fields."],
  ["Article (blog posts)", "Article", "⚠ Medium", COLORS.medium,
    "wordCount wrong by an order of magnitude (13 and 8 words on full-length posts). Content parser isn't reading real body copy."],
  ["Person (author, wendys-journey post)", "Person", "⚠ Medium", COLORS.medium,
    "name: \"sbmadmin\" — raw system username exposed as public byline instead of a real author name. Weakens E-E-A-T signals."],
  ["FAQPage (newcastle-solutions)", "FAQPage", "ℹ Info", COLORS.info,
    "No rich result since May 7, 2026 (retired sitewide). Content is accurate, so keep for AI Mode / AI Overviews grounding."],
  ["ItemList (who-we-help, how-we-help)", "ItemList", "ℹ Info", COLORS.info,
    "Items are bare Audience objects without position. No rich-result path either way — low priority."],
  ["WebPage / BreadcrumbList / WebSite (all pages)", "—", "✅ Pass", COLORS.pass,
    "Correctly structured, absolute URLs, valid dates, proper @id cross-referencing."],
  ["LocalBusiness aggregateRating (4.9 / 151 reviews)", "AggregateRating", "✅ Pass", COLORS.pass,
    "Verified genuine — matches a live \"151 Google reviews\" widget visibly rendered on the homepage. Not fabricated."],
];

const validationTable = new Table({
  width: { size: 9350, type: WidthType.DXA },
  columnWidths: [2400, 1450, 1200, 4300],
  rows: [
    new TableRow({
      tableHeader: true,
      children: [
        headerCell("Schema", 2400), headerCell("Type", 1450), headerCell("Status", 1200), headerCell("Issues", 4300),
      ],
    }),
    ...validationRows.map((r, i) =>
      new TableRow({
        children: [
          cell(r[0], { width: 2400, fill: i % 2 ? COLORS.altRow : undefined, bold: true }),
          cell(r[1], { width: 1450, fill: i % 2 ? COLORS.altRow : undefined }),
          cell(r[2], { width: 1200, fill: i % 2 ? COLORS.altRow : undefined, bold: true, color: r[3] }),
          cell(r[4], { width: 4300, fill: i % 2 ? COLORS.altRow : undefined, size: 18 }),
        ],
      })
    ),
  ],
});

const doc = new Document({
  sections: [
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 }, // US Letter
          margin: { top: 1080, bottom: 1080, left: 1080, right: 1080 },
        },
      },
      children: [
        new Paragraph({
          spacing: { after: 60 },
          children: [new TextRun({ text: "Schema Markup Audit", bold: true, size: 44, color: "1F3864", font: FONT })],
        }),
        new Paragraph({
          spacing: { after: 40 },
