const {
  Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell,
  WidthType, ShadingType, BorderStyle, AlignmentType, PageOrientation, VerticalAlign,
  ExternalHyperlink
} = require("docx");

const COLORS = {
  critical: "C00000",
  high: "E36C09",
  medium: "BF8F00",
  info: "2E74B5",
  pass: "548235",
  headerFill: "1F3864",
  altRow: "F2F2F2",
};

const FONT = "Calibri";
const MONO = "Consolas";

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 160 },
    children: [new TextRun({ text, bold: true, color: "1F3864", font: FONT })],
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 120 },
    children: [new TextRun({ text, bold: true, color: "2E74B5", font: FONT })],
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 160 },
    children: [new TextRun({ text, font: FONT, size: 22, ...opts })],
  });
}

function bullet(text, opts = {}) {
  return new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 100 },
    children: [new TextRun({ text, font: FONT, size: 22, ...opts })],
  });
}

function severityBullet(label, color, text) {
  return new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 120 },
    children: [
      new TextRun({ text: `${label}: `, bold: true, color, font: FONT, size: 22 }),
      new TextRun({ text, font: FONT, size: 22 }),
    ],
  });
}

function codeBlock(lines) {
  return new Paragraph({
    spacing: { before: 80, after: 200 },
    shading: { type: ShadingType.CLEAR, fill: "F5F5F5" },
    border: {
      top: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      bottom: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      left: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
      right: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC" },
    },
    children: lines.flatMap((line, i) => {
      const run = new TextRun({ text: line || " ", font: MONO, size: 18, color: "333333", break: i === 0 ? 0 : 1 });
      return [run];
    }),
  });
}

function cell(text, opts = {}) {
  const { bold = false, color, fill, width, align = AlignmentType.LEFT, size = 20 } = opts;
  return new TableCell({
    width: { size: width, type: WidthType.DXA },
    shading: fill ? { type: ShadingType.CLEAR, fill } : undefined,
    verticalAlign: VerticalAlign.CENTER,
    margins: { top: 80, bottom: 80, left: 100, right: 100 },
    children: [
      new Paragraph({
        alignment: align,
        children: [new TextRun({ text, bold, color, font: FONT, size })],
      }),
    ],
  });
}

function headerCell(text, width) {
